// URL base das APIs locais.
// Mantém as chamadas seguras tanto no teste quanto na live, sem depender de variável externa.
function remapApiUrl(file) {
  const cleanFile = String(file || '').replace(/^\/?api\//, '').replace(/^\//, '');
  return 'api/' + cleanFile;
}

