function getAvatar(name, size=38, radius=12, fontSize=15) {
  const img = COLLAB_AVATARS[name];
  if (img) {
    return `<img src="${img}" style="width:${size}px;height:${size}px;border-radius:${radius}px;object-fit:cover;object-position:center top;flex-shrink:0" alt="${name}" />`;
  }
  return `<div style="width:${size}px;height:${size}px;border-radius:${radius}px;background:var(--accent);display:grid;place-items:center;font-weight:800;font-size:${fontSize}px;color:#fff;flex-shrink:0">${name[0]}</div>`;
}

