function tryLS(fn) { try { return fn(); } catch(e) { return null; } }

const ARRAY_KEYS = ['entries','clients','collabs','taskPoints','descontos'];
const get = key => {
  const ls = tryLS(() => JSON.parse(localStorage.getItem('tt_' + key + '_v2') || 'null'));
  if (ls !== null && ls !== undefined) return ls;
  const stored = _store[key];
  if (stored !== undefined) return stored;
  return ARRAY_KEYS.includes(key) ? [] : {};
};
const set = (key, val) => {
  _store[key] = val;
  tryLS(() => localStorage.setItem('tt_' + key + '_v2', JSON.stringify(val)));
};
const getSession = () => {
  const ls = tryLS(() => JSON.parse(localStorage.getItem('tt_user_v2') || 'null'));
  return ls;
};
const setSession = val => tryLS(() => localStorage.setItem('tt_user_v2', JSON.stringify(val)));
const clearSession = () => tryLS(() => localStorage.removeItem('tt_user_v2'));

function normalizePersonName(name) {
  return String(name || '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/\s+/g, ' ')
    .trim()
    .toLowerCase();
}

function getKnownPersonNamesForCompare() {
  try {
    return (typeof getCollabs === 'function' ? getCollabs() : [])
      .map(c => c && c.name)
      .filter(Boolean);
  } catch (e) {
    return [];
  }
}

function canonicalPersonKeyForCompare(name) {
  const normalized = normalizePersonName(name);
  if (!normalized) return '';

  const known = [...new Set(getKnownPersonNamesForCompare().map(normalizePersonName).filter(Boolean))];
  if (!known.length) return normalized;

  const exact = known.find(k => k === normalized);
  if (exact) return exact;

  const first = normalized.split(' ')[0] || '';
  const matchesByFirst = known.filter(k => (k.split(' ')[0] || '') === first);

  // Resolve só quando o primeiro nome identifica uma única pessoa cadastrada.
  // Ex.: "Christopher Cassenoti" no registro antigo continua batendo com "Christopher".
  if (first && matchesByFirst.length === 1) return matchesByFirst[0];

  return normalized;
}

function samePersonName(a, b) {
  const ca = canonicalPersonKeyForCompare(a);
  const cb = canonicalPersonKeyForCompare(b);
  if (!ca || !cb) return false;
  return ca === cb;
}

function normalizePointValue(value) {
  if (value === null || value === undefined || value === '') return null;
  const n = Number(String(value).replace(',', '.'));
  return Number.isFinite(n) ? n : null;
}

function formatPoints(value) {
  const n = normalizePointValue(value) || 0;
  return Number.isInteger(n) ? String(n) : n.toLocaleString('pt-BR', { maximumFractionDigits: 2 });
}

function normalizeWorkEntry(entry) {
  if (!entry || typeof entry !== 'object') return null;

  const start = entry.start || entry.inicio || entry.startedAt || '';
  const end = entry.end || entry.fim || entry.finishedAt || '';
  const durationSeconds = Number(entry.durationSeconds ?? entry.duracao ?? entry.duration ?? 0) || 0;
  const rawPoints = normalizePointValue(entry.taskPoints ?? entry.points ?? entry.pontos ?? entry.pontos_final);
  const rawBasePoints = normalizePointValue(entry.baseTaskPoints ?? entry.basePoints ?? entry.pontos_base ?? entry.base_points);

  return {
    ...entry,
    id: String(entry.id || entry.uid_local || entry.uidLocal || entry.localUid || (entry.timerId ? 'timer_' + entry.timerId : '') || (entry.dbId ? 'db_' + entry.dbId : '')),
    dbId: entry.dbId ?? entry.timerId ?? entry.db_id ?? null,
    client: entry.client ?? entry.cliente ?? '',
    task: entry.task ?? entry.tarefa ?? '',
    taskDesc: entry.taskDesc ?? entry.descricao ?? entry.desc ?? '',
    category: entry.category ?? entry.categoria ?? '',
    user: entry.user ?? entry.usuario ?? entry.colaborador ?? '',
    role: entry.role ?? entry.cargo ?? '',
    start,
    end,
    date: entry.date || (start ? formatDateBR(new Date(start)) : ''),
    durationSeconds,
    taskPoints: rawPoints !== null ? rawPoints : entry.taskPoints,
    baseTaskPoints: rawBasePoints !== null ? rawBasePoints : entry.baseTaskPoints,
    pointMode: entry.pointMode || entry.modo_pontos || entry.point_mode || 'fixed',
    taskLines: Array.isArray(entry.taskLines) ? entry.taskLines : (Array.isArray(entry.task_lines) ? entry.task_lines : [])
  };
}

function getWorkEntryDedupeKeys(entry) {
  const keys = [];
  const dbId = entry?.dbId ?? entry?.timerId ?? entry?.db_id;
  if (dbId !== null && dbId !== undefined && dbId !== '') keys.push(`db:${String(dbId)}`);
  if (entry?.id) keys.push(`id:${String(entry.id)}`);

  const sigParts = [
    canonicalPersonKeyForCompare(entry?.user || ''),
    String(entry?.client || '').trim().toLowerCase(),
    String(entry?.task || '').trim().toLowerCase(),
    String(entry?.start || ''),
    String(entry?.end || ''),
    String(Number(entry?.durationSeconds || 0))
  ];
  if (sigParts.some(Boolean)) keys.push(`sig:${sigParts.join('|')}`);

  return keys.filter(Boolean);
}

function dedupeWorkEntries(entries) {
  const seen = new Set();
  const result = [];

  (Array.isArray(entries) ? entries : []).forEach(entry => {
    const keys = getWorkEntryDedupeKeys(entry);
    if (keys.some(key => seen.has(key))) return;
    keys.forEach(key => seen.add(key));
    result.push(entry);
  });

  return result;
}

function getEntries() {
  const entries = get('entries') || [];
  const normalized = Array.isArray(entries) ? entries.map(normalizeWorkEntry).filter(e => e && e.id) : [];
  return dedupeWorkEntries(normalized);
}
function getClients() { return get('clients') || []; }
function getCollabs() { return get('collabs') || []; }

function entryBelongsToUser(entry, userName = currentUser?.name) {
  return samePersonName(entry?.user, userName);
}

function entryDate(entry) {
  const d = new Date(entry?.start || entry?.inicio || entry?.date || '');
  return Number.isNaN(d.getTime()) ? new Date(0) : d;
}

function getEntryPoints(entry, fallbackRole = '') {
  if (!entry) return 0;

  const saved = normalizePointValue(entry.taskPoints ?? entry.points ?? entry.pontos ?? entry.pontos_final);
  if (saved !== null) return saved;

  const lines = Array.isArray(entry.taskLines) ? entry.taskLines : [];
  const lineTotal = lines.reduce((sum, item) => {
    const points = normalizePointValue(item.points ?? item.pontos) || 0;
    const qty = Number(item.qty ?? item.quantidade ?? 1) || 1;
    return sum + (points * qty);
  }, 0);
  if (lineTotal > 0) return lineTotal;

  return normalizePointValue(matchTaskPoints(entry.task || entry.tarefa || '', fallbackRole || entry.role || currentUser?.role || '')) || 0;
}

function getSupervisors() {
  const ls = tryLS(() => JSON.parse(localStorage.getItem('tt_supervisors_v1') || 'null'));
  if (ls) return ls;
  return _store.supervisors || {};
}
function setSupervisors(val) {
  _store.supervisors = val;
  tryLS(() => localStorage.setItem('tt_supervisors_v1', JSON.stringify(val)));
}
function isSupervisor(name) {
  return !!getSupervisors()[name];
}
function getSupervisedGroup(name) {
  const supervisors = getSupervisors() || {};
  const configured = Array.isArray(supervisors[name]) ? supervisors[name] : [];
  const collabs = getCollabs() || [];
  const collabNames = new Set(collabs.map(c => String(c.name || '')));

  // Mantém o grupo configurado, mas remove pessoas que não existem mais no banco.
  const cleanConfigured = configured
    .filter(memberName => collabNames.has(String(memberName || '')))
    .filter(memberName => String(memberName || '') !== String(name || ''));

  // Para supervisor, usa os colaboradores atuais do banco como fonte principal.
  // Isso evita a tela ficar presa no grupo antigo salvo em localStorage/app_state.
  const userIsSupervisor = !!supervisors[name] || String(currentUser?.role || '').toLowerCase().includes('supervisor');

  if (userIsSupervisor) {
    const dynamicGroup = collabs
      .filter(c => String(c.name || '') !== String(name || ''))
      .filter(c => String(c.role || '').trim().toLowerCase() !== 'diretor')
      .map(c => c.name);

    return [...new Set([...cleanConfigured, ...dynamicGroup])];
  }

  return cleanConfigured;
}
